class Solution:
    def countOfPairs(self, nums: List[int]) -> int:
        MOD = 10**9 + 7
        n = len(nums)
        dp = [[0] * (max(nums) + 1) for _ in range(n)]

        for i in range(n):
            for x in range(nums[i] + 1):
                if i == 0:
                    dp[i][x] = 1
                else:
                    for y in range(x, nums[i] + 1):
                        if (i == 0 or dp[i - 1][y] > 0) and (i == 0 or dp[i - 1][y] <= dp[i - 1][y]):
                            dp[i][x] += dp[i - 1][y]
                            dp[i][x] %= MOD
        return sum(dp[-1]) % MOD
